export function resolveExportLocale(context) {
  return context?.locale?.resolved === 'zh-CN' ? 'zh-CN' : 'en'
}

export function tExport(context, key) {
  const locale = resolveExportLocale(context)
  return messages[locale][key] ?? messages.en[key] ?? key
}

export function formatExport(context, key, replacements = {}) {
  return Object.entries(replacements).reduce(
    (message, [token, value]) => message.replaceAll(`{${token}}`, String(value)),
    tExport(context, key),
  )
}
